	"socialpredict/handlers/markets/dto"
	dmarkets "socialpredict/internal/domain/markets"
	"socialpredict/logger"
)

// Constants for backward compatibility with tests
const (
	maxQuestionTitleLength = 160
)

var errSecurityServiceUnavailable = errors.New("security service unavailable")

// Helper functions for backward compatibility with tests
func checkQuestionTitleLength(title string) error {
	if len(title) > maxQuestionTitleLength || len(title) < 1 {
		return fmt.Errorf("question title exceeds %d characters or is blank", maxQuestionTitleLength)
	}
	return nil
}

func checkQuestionDescriptionLength(description string) error {
	if len(description) > 2000 {
		return errors.New("question description exceeds 2000 characters")
	}
	return nil
}

// ValidateMarketResolutionTime - test helper function for backward compatibility
func ValidateMarketResolutionTime(resolutionTime time.Time, config *setup.EconomicConfig) error {
	now := time.Now()
	minimumDuration := time.Duration(config.Economics.MarketCreation.MinimumFutureHours * float64(time.Hour))
	minimumFutureTime := now.Add(minimumDuration)

	if resolutionTime.Before(minimumFutureTime) || resolutionTime.Equal(minimumFutureTime) {
		return fmt.Errorf("market resolution time must be at least %.1f hours in the future",
			config.Economics.MarketCreation.MinimumFutureHours)
	}
	return nil
}

type CreateMarketService struct {
	svc             dmarkets.Service
	auth            authsvc.Authenticator
	securityService *security.SecurityService
}

func NewCreateMarketService(svc dmarkets.Service, auth authsvc.Authenticator, securityService *security.SecurityService) *CreateMarketService {
	return &CreateMarketService{
		svc:             svc,
		auth:            auth,
		securityService: securityService,
	}
}

func (h *CreateMarketService) currentUser(r *http.Request) (*dusers.User, *authsvc.AuthError) {
	if h.auth == nil {
		return nil, &authsvc.AuthError{Kind: authsvc.ErrorKindServiceUnavailable, Message: "authentication service unavailable"}
	}
	return h.auth.CurrentUser(r)
}

func (h *CreateMarketService) Handle(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method is not supported.", http.StatusMethodNotAllowed)
		return
	}

	user, httpErr := h.currentUser(r)
	if httpErr != nil {
		logger.LogWarn("CreateMarket", "CurrentUser", httpErr.Message)
		http.Error(w, httpErr.Error(), authhttp.StatusCode(httpErr))
		return
	}

	req, decodeErr := decodeCreateMarketRequest(r)
	if decodeErr != nil {
		logger.LogWarn("CreateMarket", "DecodeRequest", decodeErr.Error())
		http.Error(w, decodeErr.Error(), http.StatusBadRequest)
		return
	}

	sanitized, sanitizeErr := sanitizeMarketRequest(h.securityService, req)
	if sanitizeErr != nil {
		logger.LogWarn("CreateMarket", "SanitizeMarketRequest", sanitizeErr.Error())
		writeCreateMarketSanitizationError(w, sanitizeErr)
		return
	}

	domainReq := toDomainCreateRequest(sanitized)

	market, err := h.svc.CreateMarket(context.Background(), domainReq, user.Username)
	if err != nil {
		writeCreateMarketError(w, err)
		logCreateMarketFailure(user.Username, err)
		return
	}

	response := toCreateMarketResponse(market)

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(response)
	logger.LogInfo("CreateMarket", "CreateMarket", fmt.Sprintf("Created market %d by user %s", market.ID, user.Username))
}

// CreateMarketHandlerWithService creates a handler with service injection
func CreateMarketHandlerWithService(svc dmarkets.ServiceInterface, auth authsvc.Authenticator, econConfig *setup.EconomicConfig, securityService *security.SecurityService) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "Method is not supported.", http.StatusMethodNotAllowed)
			return
		}

		user, httpErr := currentUserOrError(w, r, auth)
		if httpErr != nil {
			return
		}

		req, decodeErr := decodeCreateMarketRequest(r)
		if decodeErr != nil {
			logger.LogWarn("CreateMarket", "DecodeRequest", decodeErr.Error())
			http.Error(w, decodeErr.Error(), http.StatusBadRequest)
			return
		}

		sanitized, sanitizeErr := sanitizeMarketRequest(securityService, req)
		if sanitizeErr != nil {
			logger.LogWarn("CreateMarket", "SanitizeMarketRequest", sanitizeErr.Error())
			writeCreateMarketSanitizationError(w, sanitizeErr)
			return
		}

		domainReq := toDomainCreateRequest(sanitized)

		market, err := svc.CreateMarket(r.Context(), domainReq, user.Username)
		if err != nil {
			writeCreateMarketError(w, err)
			logCreateMarketFailure(user.Username, err)
			return
		}

		response := toCreateMarketResponse(market)

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusCreated)
		json.NewEncoder(w).Encode(response)
		logger.LogInfo("CreateMarket", "CreateMarket", fmt.Sprintf("Created market %d by user %s", market.ID, user.Username))
	}
}

func decodeCreateMarketRequest(r *http.Request) (dto.CreateMarketRequest, error) {
	var req dto.CreateMarketRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return dto.CreateMarketRequest{}, fmt.Errorf("Error reading request body")
	}
	return req, nil
}

func sanitizeMarketRequest(securityService *security.SecurityService, req dto.CreateMarketRequest) (dto.CreateMarketRequest, error) {
	if securityService == nil {
		return dto.CreateMarketRequest{}, errSecurityServiceUnavailable
	}
	marketInput := security.MarketInput{
		Title:       req.QuestionTitle,
		Description: req.Description,
		EndTime:     req.ResolutionDateTime.String(),
	}

	sanitizedInput, err := securityService.ValidateAndSanitizeMarketInput(marketInput)
	if err != nil {
		return dto.CreateMarketRequest{}, err
	}

	req.QuestionTitle = sanitizedInput.Title
	req.Description = sanitizedInput.Description
	return req, nil
}

func writeCreateMarketSanitizationError(w http.ResponseWriter, err error) {
	if errors.Is(err, errSecurityServiceUnavailable) {
		http.Error(w, "security service unavailable", http.StatusInternalServerError)
		return
	}
	http.Error(w, "Invalid market data: "+err.Error(), http.StatusBadRequest)
}

func toDomainCreateRequest(req dto.CreateMarketRequest) dmarkets.MarketCreateRequest {
	return dmarkets.MarketCreateRequest{
		QuestionTitle:      req.QuestionTitle,
		Description:        req.Description,
		OutcomeType:        req.OutcomeType,
		ResolutionDateTime: req.ResolutionDateTime,
		YesLabel:           req.YesLabel,
		NoLabel:            req.NoLabel,
	}
}

func toCreateMarketResponse(market *dmarkets.Market) dto.CreateMarketResponse {
	return dto.CreateMarketResponse{
		ID:                 market.ID,
		QuestionTitle:      market.QuestionTitle,
		Description:        market.Description,
		OutcomeType:        market.OutcomeType,
		ResolutionDateTime: market.ResolutionDateTime,
		CreatorUsername:    market.CreatorUsername,
		YesLabel:           market.YesLabel,
		NoLabel:            market.NoLabel,
		Status:             market.Status,
		CreatedAt:          market.CreatedAt,
	}
}

func currentUserOrError(w http.ResponseWriter, r *http.Request, auth authsvc.Authenticator) (*dusers.User, *authsvc.AuthError) {
	if auth == nil {
		logger.LogError("CreateMarket", "CurrentUser", errors.New("authentication service unavailable"))
		http.Error(w, "authentication service unavailable", http.StatusInternalServerError)
		return nil, &authsvc.AuthError{Kind: authsvc.ErrorKindServiceUnavailable, Message: "authentication service unavailable"}
	}
	user, httperr := auth.CurrentUser(r)
	if httperr != nil {
		logger.LogWarn("CreateMarket", "CurrentUser", httperr.Message)
		http.Error(w, httperr.Error(), authhttp.StatusCode(httperr))
		return nil, httperr
	}
	return user, nil
}

func writeCreateMarketError(w http.ResponseWriter, err error) {
	switch err {
	case dmarkets.ErrUserNotFound:
		http.Error(w, "User not found", http.StatusNotFound)
	case dmarkets.ErrInsufficientBalance:
		http.Error(w, "Insufficient balance", http.StatusBadRequest)
	case dmarkets.ErrInvalidQuestionLength,
		dmarkets.ErrInvalidDescriptionLength,
		dmarkets.ErrInvalidLabel,
		dmarkets.ErrInvalidResolutionTime:
		http.Error(w, err.Error(), http.StatusBadRequest)
	default:
		http.Error(w, "Error creating market", http.StatusInternalServerError)
	}
}

func logCreateMarketFailure(username string, err error) {
	message := fmt.Sprintf("Create market failed for user %s: %v", username, err)

package marketshandlers

import (
	"context"
	"errors"
	"net/http"

	"socialpredict/handlers"
	"socialpredict/handlers/markets/dto"
	dmarkets "socialpredict/internal/domain/markets"
	"socialpredict/logger"
	"socialpredict/security"
)

// SearchMarketsHandler handles HTTP requests for searching markets - HTTP-only with service injection
func SearchMarketsHandler(svc dmarkets.ServiceInterface, securityService *security.SecurityService) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		handleSearchMarkets(w, r, svc, securityService)
	}
}

type searchRequestParams struct {
	query   string
	filters dmarkets.SearchFilters
}

type httpError struct {
	message    string
	statusCode int
}

func parseSearchRequest(r *http.Request, securityService *security.SecurityService) (searchRequestParams, *httpError) {
	query, queryErr := extractQuery(r)
	if queryErr != nil {
		return searchRequestParams{}, queryErr
	}

	sanitizedQuery, sanitizeErr := sanitizeQuery(query, securityService)
	if sanitizeErr != nil {
		return searchRequestParams{}, sanitizeErr
	}

	return buildSearchRequestParams(r, sanitizedQuery)
}

func extractQuery(r *http.Request) (string, *httpError) {
	for _, key := range []string{"query", "q"} {
		if value := r.URL.Query().Get(key); value != "" {
			return value, nil
		}
	}
	return "", &httpError{message: "Query parameter 'query' is required", statusCode: http.StatusBadRequest}
}

func sanitizeQuery(query string, securityService *security.SecurityService) (string, *httpError) {
	if securityService == nil || securityService.Sanitizer == nil {
		return "", &httpError{message: "Security service unavailable", statusCode: http.StatusInternalServerError}
	}

	sanitizedQuery, err := securityService.Sanitizer.SanitizeMarketTitle(query)
	if err != nil {
		logger.LogWarn("SearchMarkets", "SanitizeQuery", "sanitization failed for query '"+query+"': "+err.Error())
		return "", &httpError{message: "Invalid search query: " + err.Error(), statusCode: http.StatusBadRequest}
	}
	if len(sanitizedQuery) > 100 {
		return "", &httpError{message: "Query too long (max 100 characters)", statusCode: http.StatusBadRequest}
	}
	return sanitizedQuery, nil
}

func parseLimit(rawLimit string) int {
	return parseBoundedInt(rawLimit, 20, 1, 50)
}

func parseOffset(rawOffset string) int {
	return parseBoundedInt(rawOffset, 0, 0, int(^uint(0)>>1))
}

func buildSearchResponse(ctx context.Context, svc dmarkets.ServiceInterface, searchResults *dmarkets.SearchResults) (dto.SearchResponse, error) {
	primaryOverviews, err := buildSearchResultSet(ctx, svc, searchResults.PrimaryResults)
	if err != nil {
		logger.LogError("SearchMarkets", "BuildPrimaryResults", err)
		return dto.SearchResponse{}, errors.New("Error building primary results")
	}

	fallbackOverviews, err := buildSearchResultSet(ctx, svc, searchResults.FallbackResults)
	if err != nil {
		logger.LogError("SearchMarkets", "BuildFallbackResults", err)
		return dto.SearchResponse{}, errors.New("Error building fallback results")
	}

	return dto.SearchResponse{
		PrimaryResults:  primaryOverviews,
		FallbackResults: fallbackOverviews,
		Query:           searchResults.Query,
		PrimaryStatus:   searchResults.PrimaryStatus,
		PrimaryCount:    searchResults.PrimaryCount,
		FallbackCount:   searchResults.FallbackCount,
		TotalCount:      searchResults.TotalCount,
		FallbackUsed:    searchResults.FallbackUsed,
	}, nil
}

func buildSearchRequestParams(r *http.Request, query string) (searchRequestParams, *httpError) {
	filters, filtersErr := parseSearchFilters(r)
	if filtersErr != nil {
		return searchRequestParams{}, filtersErr
	}

	return searchRequestParams{
		query:   query,
		filters: filters,
	}, nil
}

func parseSearchFilters(r *http.Request) (dmarkets.SearchFilters, *httpError) {
	status, err := normalizeStatusParam(r.URL.Query().Get("status"))
	if err != nil {
		return dmarkets.SearchFilters{}, &httpError{message: err.Error(), statusCode: http.StatusBadRequest}
	}

	return dmarkets.SearchFilters{
		Status: status,
		Limit:  parseLimit(r.URL.Query().Get("limit")),
		Offset: parseOffset(r.URL.Query().Get("offset")),
	}, nil
}

func searchMarkets(ctx context.Context, svc dmarkets.ServiceInterface, params searchRequestParams) (*dmarkets.SearchResults, error) {
	return svc.SearchMarkets(ctx, params.query, params.filters)
}

func buildSearchResultSet(ctx context.Context, svc dmarkets.ServiceInterface, markets []*dmarkets.Market) ([]*dto.MarketOverviewResponse, error) {
	return buildMarketOverviewResponses(ctx, svc, markets)
}

func writeSearchResponse(w http.ResponseWriter, ctx context.Context, svc dmarkets.ServiceInterface, searchResults *dmarkets.SearchResults) error {
	response, err := buildSearchResponse(ctx, svc, searchResults)
	if err != nil {
		return err
	}

	if err := writeJSON(w, http.StatusOK, response); err != nil {
		logger.LogError("SearchMarkets", "EncodeResponse", err)
		return err
	}

	return nil
}

func writeSearchError(w http.ResponseWriter, err error) {
	switch {
	case errors.Is(err, dmarkets.ErrInvalidInput):
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
	default:
		logger.LogError("SearchMarkets", "SearchMarkets", err)
		writeInternalError(w)
	}
}

func handleSearchMarkets(w http.ResponseWriter, r *http.Request, svc dmarkets.ServiceInterface, securityService *security.SecurityService) {
	if r.Method != http.MethodGet {
		writeMethodNotAllowed(w)
		return
	}
	if securityService == nil || securityService.Sanitizer == nil {
		writeInternalError(w)
		return
	}

	params, clientErr := parseSearchRequest(r, securityService)
	if clientErr != nil {
		_ = handlers.WriteFailure(w, clientErr.statusCode, handlers.ReasonInvalidRequest)
		return
	}

	searchResults, err := searchMarkets(r.Context(), svc, params)
	if err != nil {
		writeSearchError(w, err)
		return
	}

	if err := writeSearchResponse(w, r.Context(), svc, searchResults); err != nil {
		if isRequestCanceled(err) {
			return
		}
		logger.LogError("SearchMarkets", "WriteResponse", err)
		writeInternalError(w)
	}
}

